    83→/// Arguments for vvx_commit command (wraps vvc)
    84→#[derive(clap::Args, Debug)]
    85→struct CommitArgs {
    86→    /// Prefix string to prepend to commit message
    87→    #[arg(long)]
    88→    prefix: Option<String>,
    89→
    90→    /// Commit message; if absent, invoke claude to generate from diff
    91→    #[arg(short, long)]
    92→    message: Option<String>,
    93→
    94→    /// Allow empty commits
    95→    #[arg(long)]
    96→    allow_empty: bool,
    97→
    98→    /// Skip 'git add -A' (respect pre-staged files)
    99→    #[arg(long)]
   100→    no_stage: bool,
   101→}
