   246→/// Dispatch external subcommands to appropriate kit CLIs
   247→async fn dispatch_external(args: Vec<OsString>) -> i32 {
   248→    if args.is_empty() {
   249→        eprintln!("vvx: error: no subcommand provided");
   250→        return 1;
   251→    }
   252→
   253→    let cmd_name = args[0].to_string_lossy();
   254→
   255→    // Delegate to JJK if available and command matches
   256→    #[cfg(feature = "jjk")]
   257→    if jjk::jjrx_is_jjk_command(&cmd_name) {
   258→        return jjk::jjrx_dispatch(&args).await;
   259→    }
   260→
   261→    // Unknown external subcommand
   262→    eprintln!("vvx: error: unknown command '{}'", cmd_name);
   263→    eprintln!("Run 'vvx --help' for available commands");
   264→    1
   265→}
