   267→/// Lock reference path for push operations (same as commit to prevent concurrent ops)
   268→const LOCK_REF: &str = "refs/vvg/locks/vvx";
   269→
   270→/// Force-break a stuck lock
   271→fn run_unlock() -> i32 {
   272→    use std::process::Command;
   273→
   274→    // Check if lock exists
   275→    let check = Command::new("git")
   276→        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
   277→        .status();
   278→
   279→    match check {
   280→        Ok(status) if status.success() => {
   281→            // Lock exists, delete it
   282→            let delete = Command::new("git")
   283→                .args(["update-ref", "-d", LOCK_REF])
   284→                .output();
   285→
   286→            match delete {
   287→                Ok(output) if output.status.success() => {
   288→                    eprintln!("unlock: lock broken successfully");
   289→                    0
   290→                }
   291→                Ok(output) => {
   292→                    eprintln!("unlock: error: failed to delete lock: {}",
   293→                        String::from_utf8_lossy(&output.stderr));
   294→                    1
   295→                }
   296→                Err(e) => {
   297→                    eprintln!("unlock: error: {}", e);
   298→                    1
   299→                }
   300→            }
   301→        }
   302→        Ok(_) => {
   303→            // Lock doesn't exist
   304→            eprintln!("unlock: no lock held");
   305→            0
   306→        }
   307→        Err(e) => {
   308→            eprintln!("unlock: error checking lock: {}", e);
   309→            1
   310→        }
   311→    }
   312→}
