   314→fn run_push(args: PushArgs) -> i32 {
   315→    use std::process::Command;
   316→
   317→    eprintln!("push: acquiring lock...");
   318→    let head_output = Command::new("git")
   319→        .args(["rev-parse", "HEAD"])
   320→        .output();
   321→
   322→    let lock_value = match head_output {
   323→        Ok(output) if output.status.success() => {
   324→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   325→        }
   326→        _ => "0000000000000000000000000000000000000000".to_string(),
   327→    };
   328→
   329→    let lock_result = Command::new("git")
   330→        .args(["update-ref", LOCK_REF, &lock_value, ""])
   331→        .output();
   332→
   333→    match lock_result {
   334→        Ok(output) if output.status.success() => {
   335→            // Lock acquired
   336→        }
   337→        _ => {
   338→            eprintln!("push: error: Another operation in progress - lock held");
   339→            return 1;
   340→        }
   341→    }
   342→
   343→    let result = run_push_workflow(&args);
   344→
   345→    let _ = Command::new("git")
   346→        .args(["update-ref", "-d", LOCK_REF])
   347→        .output();
   348→
   349→    match result {
   350→        Ok(()) => {
   351→            eprintln!("push: success");
   352→            0
   353→        }
   354→        Err(e) => {
   355→            eprintln!("push: error: {}", e);
   356→            1
   357→        }
   358→    }
   359→}
   360→
   361→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   362→    use std::process::Command;
   363→
   364→    let branch = match &args.branch {
   365→        Some(b) => b.clone(),
   366→        None => {
   367→            let output = Command::new("git")
   368→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   369→                .output()
   370→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   371→
   372→            if !output.status.success() {
   373→                return Err("Failed to determine current branch".to_string());
   374→            }
   375→
   376→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   377→        }
   378→    };
   379→
   380→    eprintln!("push: pushing {} to {}", branch, args.remote);
   381→
   382→    let mut push_args = vec!["push", &args.remote, &branch];
   383→    if args.force {
   384→        push_args.push("--force");
   385→    }
   386→
   387→    let output = Command::new("git")
   388→        .args(&push_args)
   389→        .output()
   390→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   391→
   392→    if !output.status.success() {
   393→        let stderr = String::from_utf8_lossy(&output.stderr);
   394→        return Err(format!("git push failed: {}", stderr));
   395→    }
   396→
   397→    Ok(())
   398→}
